/**
 * Filters active users using member function idiom.
 *
 * @users Input user rows.
 * @return array
 */
public array function filterActiveUsers(required array users) {
  return arguments.users.filter(function(required struct userRow) {
    return userRow.status == 'active';
  });
}

/**
 * Maps users to DTO shape with member function map().
 *
 * @users Input users.
 * @return array
 */
public array function mapUserDtos(required array users) {
  return arguments.users.map(function(required struct userRow) {
    return { id: userRow.id, email: userRow.email };
  });
}

/**
 * Resolves optional sort value with modern fallback idiom.
 *
 * @rc Request collection.
 * @return string
 */
public string function resolveSort(required struct rc) {
  return arguments.rc.sort ?: 'createdAt';
}

wrong:
// Wrong: verbose if/structKeyExists fallback instead of null-coalescing Elvis operator
public string function resolveSort(required struct rc) {
  if (structKeyExists(arguments.rc, 'sort') && len(arguments.rc.sort)) {
    return arguments.rc.sort;
  }
  return 'createdAt';
}

