/**
 * Resolves per-page value using concise modern idiom.
 *
 * @rc Request collection.
 * @return numeric
 */
public numeric function resolvePerPage(required struct rc) {
  return val(arguments.rc.perPage ?: 25);
}

/**
 * Returns unique lower-cased tags using modern chain.
 *
 * @tags Raw tags list.
 * @return array
 */
public array function normalizeTags(required array tags) {
  return arguments.tags
    .map(function(required string tag) { return lCase(trim(tag)); })
    .filter(function(required string tag) { return len(tag) > 0; })
    .reduce(function(required array acc, required string tag) {
      if (!acc.contains(tag)) {
        acc.append(tag);
      }
      return acc;
    }, []);
}

/**
 * Counts failed jobs using member-function filtering.
 *
 * @jobs Job result rows.
 * @return numeric
 */
public numeric function countFailed(required array jobs) {
  return arguments.jobs.filter(function(required struct jobRow) {
    return jobRow.state == 'failed';
  }).len();
}

/**
 * Builds CSV from ids using concise modern idiom.
 *
 * @rows Input rows with id field.
 * @return string
 */
public string function toCsvIds(required array rows) {
  return arrayToList(
    arguments.rows.map(function(required struct row) { return row.id; }),
    ','
  );
}

/**
 * Builds normalized status model from input flags.
 *
 * @isActive Indicates active state.
 * @isLocked Indicates locked state.
 * @return struct
 */
public struct function buildStatusModel(required boolean isActive, required boolean isLocked) {
  return {
    state: arguments.isLocked ? 'locked' : (arguments.isActive ? 'active' : 'inactive'),
    canLogin: arguments.isActive && !arguments.isLocked
  };
}

